import{_ as t,o as d,c as e,a4 as a}from"./chunks/framework.BMymQDdR.js";const u=JSON.parse('{"title":"打包发布","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Package-Release.md","filePath":"zh/v3/designer/Package-Release.md","lastUpdated":1780630099000}'),o={name:"v3/designer/Package-Release.md"},s=a(`<h1 id="打包发布" tabindex="-1">打包发布 <a class="header-anchor" href="#打包发布" aria-label="Permalink to &quot;打包发布&quot;">​</a></h1><p>ENERGY Designer 支持多平台安装包制作，可将编译后的应用程序打包为各平台标准的安装格式。通过 <strong>设置 &gt; 构建选项</strong>（快捷键 <code>Ctrl+F9</code> / macOS <code>Cmd+F9</code>）切换到&quot;打包配置&quot;标签页进行设置。</p><h2 id="通用配置" tabindex="-1">通用配置 <a class="header-anchor" href="#通用配置" aria-label="Permalink to &quot;通用配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值</th></tr></thead><tbody><tr><td>安装包名称</td><td>生成的安装包文件名</td><td>文本输入</td><td>项目名称</td></tr></tbody></table><h2 id="macos-打包" tabindex="-1">macOS 打包 <a class="header-anchor" href="#macos-打包" aria-label="Permalink to &quot;macOS 打包&quot;">​</a></h2><h3 id="打包格式" tabindex="-1">打包格式 <a class="header-anchor" href="#打包格式" aria-label="Permalink to &quot;打包格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>PKG 安装包</td><td>macOS 标准安装包格式</td><td>开启</td></tr><tr><td>DMG 镜像</td><td>macOS 磁盘映像文件</td><td>关闭</td></tr><tr><td>通用二进制 (Universal Binary)</td><td>同时支持 Intel (amd64) 和 Apple Silicon (arm64) 架构</td><td>关闭</td></tr></tbody></table><p><strong>通用二进制说明：</strong> 启用后，构建会自动分别编译 amd64 和 arm64 架构的临时二进制，然后使用 <code>lipo</code> 工具合并为 Universal Binary。需安装 Xcode Command Line Tools。</p><h3 id="签名配置" tabindex="-1">签名配置 <a class="header-anchor" href="#签名配置" aria-label="Permalink to &quot;签名配置&quot;">​</a></h3><p>签名功能通过启用/禁用按钮控制开关。配置内容为 <code>codesign</code> 命令列表，每行一条命令。</p><p><strong>默认签名命令：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codesign -f -s &quot;-&quot; &quot;$APP_NAME/Contents/Frameworks/$ENERGY.DYLIB&quot;</span></span>
<span class="line"><span>codesign -f -s &quot;-&quot; --options runtime &quot;$APP_NAME&quot;</span></span></code></pre></div><p><strong>说明：</strong></p><ul><li><code>-s &quot;-&quot;</code> 表示 ad-hoc 签名（预览运行时使用）</li><li>发布时可替换为开发者证书签名</li><li><code>--options runtime</code> 启用 hardened runtime（公证要求）</li></ul><h3 id="关联文件" tabindex="-1">关联文件 <a class="header-anchor" href="#关联文件" aria-label="Permalink to &quot;关联文件&quot;">​</a></h3><p>配置应用程序关联的文件类型，每行一条记录，使用 <code>|</code> 分隔字段：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>扩展名 | 类名 | 类型描述 | 角色 | 优先级 | 图标 | MIME类型</span></span></code></pre></div><p><strong>字段说明：</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>可选值</th></tr></thead><tbody><tr><td>扩展名</td><td>文件扩展名（不含点号）</td><td>如 <code>txt</code>、<code>pdf</code></td></tr><tr><td>类名</td><td>唯一的文件类型标识符</td><td>如 <code>AppTxtFile</code></td></tr><tr><td>类型描述</td><td>文件类型的描述文字</td><td>如 <code>Text Document</code></td></tr><tr><td>角色</td><td>应用对该文件类型的角色</td><td><code>Editor</code>（编辑器）/ <code>Viewer</code>（查看器）</td></tr><tr><td>优先级</td><td>关联优先级</td><td><code>Owner</code>（所有者）/ <code>Default</code>（默认）</td></tr><tr><td>图标</td><td>关联图标文件名</td><td>如 <code>MyIcon.icns</code></td></tr><tr><td>MIME 类型</td><td>MIME 类型标识</td><td>如 <code>application/x-gproj</code></td></tr></tbody></table><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt | AppTxtFile | Text Document | Editor | Owner | MyIcon.icns | text/plain</span></span></code></pre></div><h3 id="关联协议" tabindex="-1">关联协议 <a class="header-anchor" href="#关联协议" aria-label="Permalink to &quot;关联协议&quot;">​</a></h3><p>配置应用程序关联的 URL 协议，每行一条记录，使用 <code>|</code> 分隔：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>协议名称 | 协议描述</span></span></code></pre></div><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>myapp | Open My App</span></span></code></pre></div><h2 id="windows-打包" tabindex="-1">Windows 打包 <a class="header-anchor" href="#windows-打包" aria-label="Permalink to &quot;Windows 打包&quot;">​</a></h2><h3 id="打包格式-1" tabindex="-1">打包格式 <a class="header-anchor" href="#打包格式-1" aria-label="Permalink to &quot;打包格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>EXE 安装包 (MakeNsis)</td><td>使用 NSIS 脚本生成 Windows 安装程序</td><td>开启</td></tr><tr><td>MSIX 安装包 (MakeAppx)</td><td>Windows 应用商店格式</td><td>关闭</td></tr></tbody></table><h3 id="默认安装路径" tabindex="-1">默认安装路径 <a class="header-anchor" href="#默认安装路径" aria-label="Permalink to &quot;默认安装路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>示例</th></tr></thead><tbody><tr><td>默认安装路径</td><td>应用程序的默认安装目录</td><td>文本输入</td><td><code>C:\\Program Files</code></td></tr></tbody></table><h3 id="签名配置-1" tabindex="-1">签名配置 <a class="header-anchor" href="#签名配置-1" aria-label="Permalink to &quot;签名配置&quot;">​</a></h3><p>签名功能通过启用/禁用按钮控制开关。配置内容为 <code>signtool</code> 命令，格式为 <code>key=value</code>，每行一条。</p><p><strong>签名模式：</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>格式</th><th>说明</th></tr></thead><tbody><tr><td>auto</td><td><code>auto=signtool sign /a /fd SHA256 /tr http://timestamp.digicert.com /td SHA256</code></td><td>自动选择证书</td></tr><tr><td>file</td><td><code>file=signtool sign /f cert.pfx /p 密码 /fd SHA256 /tr http://timestamp.digicert.com /td SHA256</code></td><td>指定证书文件路径和密码</td></tr></tbody></table><p><strong>说明：</strong></p><ul><li><code>/a</code> - 自动选择最佳证书</li><li><code>/fd SHA256</code> - 文件摘要算法</li><li><code>/tr</code> - 时间戳服务器 URL</li><li><code>/td SHA256</code> - 时间戳摘要算法</li><li><code>/f</code> - 证书文件路径</li><li><code>/p</code> - 证书密码</li></ul><h3 id="关联文件-1" tabindex="-1">关联文件 <a class="header-anchor" href="#关联文件-1" aria-label="Permalink to &quot;关联文件&quot;">​</a></h3><p>配置应用程序关联的文件类型，每行一条记录，使用 <code>|</code> 分隔：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>扩展名 | 唯一类名 | 类型描述 | 图标 | 右键菜单文本</span></span></code></pre></div><p><strong>字段说明：</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>扩展名</td><td>文件扩展名（不含点号）</td><td><code>txt</code></td></tr><tr><td>唯一类名</td><td>注册表中的文件类型标识</td><td><code>AppTxtFile</code></td></tr><tr><td>类型描述</td><td>文件类型的描述文字</td><td><code>My Project File</code></td></tr><tr><td>图标</td><td>关联图标文件名</td><td><code>MyFile.ico</code></td></tr><tr><td>右键菜单文本</td><td>右键菜单中显示的操作文本</td><td><code>Open with Your App</code></td></tr></tbody></table><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt | AppTxtFile | My Project File | MyFile.ico | Open with Your App</span></span></code></pre></div><h3 id="关联协议-1" tabindex="-1">关联协议 <a class="header-anchor" href="#关联协议-1" aria-label="Permalink to &quot;关联协议&quot;">​</a></h3><p>配置应用程序关联的 URL 协议，每行一条记录，使用 <code>|</code> 分隔：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>协议名称 | 协议描述</span></span></code></pre></div><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>myapp | Open My App</span></span></code></pre></div><h3 id="nsis-安装包资源" tabindex="-1">NSIS 安装包资源 <a class="header-anchor" href="#nsis-安装包资源" aria-label="Permalink to &quot;NSIS 安装包资源&quot;">​</a></h3><p>配置 NSIS 安装程序的视觉资源，格式为 <code>key=value</code>，每行一条：</p><table tabindex="0"><thead><tr><th>键名</th><th>说明</th><th>支持格式</th></tr></thead><tbody><tr><td>welcome</td><td>欢迎页面横幅图片</td><td><code>.png</code> / <code>.bmp</code></td></tr><tr><td>header</td><td>安装程序头部横幅图片</td><td><code>.png</code> / <code>.bmp</code></td></tr><tr><td>icon</td><td>安装程序图标</td><td><code>.png</code> / <code>.ico</code></td></tr><tr><td>unicon</td><td>卸载程序图标</td><td><code>.png</code> / <code>.ico</code></td></tr></tbody></table><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>welcome=assets/welcome.png</span></span>
<span class="line"><span>header=assets/header.bmp</span></span>
<span class="line"><span>icon=assets/app.ico</span></span>
<span class="line"><span>unicon=assets/uninstall.ico</span></span></code></pre></div><h3 id="nsis-许可证" tabindex="-1">NSIS 许可证 <a class="header-anchor" href="#nsis-许可证" aria-label="Permalink to &quot;NSIS 许可证&quot;">​</a></h3><p>在文本框中输入许可证协议内容，打包时自动生成 UTF-8 BOM 编码的 <code>resources/&lt;项目名&gt;-license.txt</code> 文件并嵌入安装程序。</p><h3 id="appx-资源" tabindex="-1">AppX 资源 <a class="header-anchor" href="#appx-资源" aria-label="Permalink to &quot;AppX 资源&quot;">​</a></h3><p>配置 MSIX/AppX 打包所需的资源文件，格式为 <code>key=value</code>，每行一条：</p><table tabindex="0"><thead><tr><th>键名</th><th>说明</th></tr></thead><tbody><tr><td>propertiesLogo</td><td>属性页面 Logo</td></tr><tr><td>square44x44Logo</td><td>44×44 方形图标（任务栏等）</td></tr><tr><td>square150x150Logo</td><td>150×150 方形图标（开始菜单）</td></tr><tr><td>wide310x150Logo</td><td>310×150 宽幅图标（磁贴）</td></tr><tr><td>splashScreen</td><td>启动画面图片</td></tr><tr><td>associateFileIcon</td><td>文件关联图标</td></tr><tr><td>associateProtocolLogo</td><td>协议关联 Logo</td></tr></tbody></table><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>propertiesLogo=assets/StoreLogo.png</span></span>
<span class="line"><span>square44x44Logo=assets/Square44x44Logo.png</span></span>
<span class="line"><span>square150x150Logo=assets/Square150x150Logo.png</span></span>
<span class="line"><span>wide310x150Logo=assets/Wide310x150Logo.png</span></span>
<span class="line"><span>splashScreen=assets/SplashScreen.png</span></span></code></pre></div><h2 id="linux-打包" tabindex="-1">Linux 打包 <a class="header-anchor" href="#linux-打包" aria-label="Permalink to &quot;Linux 打包&quot;">​</a></h2><h3 id="打包格式-2" tabindex="-1">打包格式 <a class="header-anchor" href="#打包格式-2" aria-label="Permalink to &quot;打包格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>deb</td><td>Debian/Ubuntu 安装包</td><td>开启</td></tr><tr><td>rpm</td><td>Red Hat/CentOS/Fedora 安装包</td><td>关闭</td></tr><tr><td>AppImage</td><td>通用 Linux 应用格式（免安装）</td><td>关闭</td></tr></tbody></table><h3 id="配置参数" tabindex="-1">配置参数 <a class="header-anchor" href="#配置参数" aria-label="Permalink to &quot;配置参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值</th><th>示例</th></tr></thead><tbody><tr><td>依赖包列表</td><td>应用运行所需的系统依赖包</td><td>文本输入</td><td>空</td><td><code>libc6 (&gt;= 2.17), libgtk-3-0</code></td></tr><tr><td>应用分类</td><td>应用在桌面环境中的分类</td><td>文本输入</td><td><code>Utility;</code></td><td><code>Development;Utility;</code></td></tr><tr><td>项目主页</td><td>应用的官方网站地址</td><td>文本输入</td><td>空</td><td><code>https://example.com</code></td></tr><tr><td>维护者</td><td>安装包维护者信息</td><td>文本输入</td><td>空</td><td><code>Name &lt;email@example.com&gt;</code></td></tr><tr><td>开源协议</td><td>应用的开源许可证</td><td>文本输入</td><td><code>MIT</code></td><td><code>GPL-3.0</code></td></tr></tbody></table><h3 id="依赖包格式规则" tabindex="-1">依赖包格式规则 <a class="header-anchor" href="#依赖包格式规则" aria-label="Permalink to &quot;依赖包格式规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>基本格式</td><td>包名 + 版本约束</td><td><code>libc6 (&gt;= 2.17)</code></td></tr><tr><td>多个依赖</td><td>逗号分隔</td><td><code>libc6 (&gt;= 2.17), libgtk-3-0</code></td></tr><tr><td>备选依赖</td><td>管道符分隔（RPM 仅取第一个）</td><td><code>libssl1.1 | libssl3</code></td></tr></tbody></table><p><strong>运行时库自动选择规则：</strong></p><table tabindex="0"><thead><tr><th>GUI 渲染框架</th><th>UI 配置</th><th>运行时库选择</th></tr></thead><tbody><tr><td>LCL</td><td>GTK2</td><td>GTK2</td></tr><tr><td>LCL</td><td>GTK3</td><td>GTK3</td></tr><tr><td>LCL + WV</td><td>-</td><td>GTK3</td></tr><tr><td>LCL + CEF</td><td>-</td><td>GTK3</td></tr></tbody></table><h2 id="打包产物汇总" tabindex="-1">打包产物汇总 <a class="header-anchor" href="#打包产物汇总" aria-label="Permalink to &quot;打包产物汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>格式</th><th>生成工具</th><th>前置要求</th></tr></thead><tbody><tr><td>macOS</td><td><code>.app</code></td><td>内置</td><td>无</td></tr><tr><td>macOS</td><td><code>.pkg</code></td><td><code>pkgbuild</code></td><td>系统内置</td></tr><tr><td>macOS</td><td><code>.dmg</code></td><td><code>create-dmg</code></td><td><code>brew install create-dmg</code></td></tr><tr><td>Windows</td><td><code>.exe</code> 安装包</td><td>NSIS</td><td>需安装 NSIS</td></tr><tr><td>Windows</td><td>AppX</td><td><code>makeappx.exe</code></td><td>需安装 Windows SDK</td></tr><tr><td>Linux</td><td><code>.deb</code></td><td><code>dpkg-deb</code></td><td>需安装 <code>dpkg-dev</code></td></tr><tr><td>Linux</td><td><code>.rpm</code></td><td><code>rpmbuild</code></td><td>需安装 <code>rpm-build</code></td></tr><tr><td>Linux</td><td><code>.AppImage</code></td><td>内置</td><td>需安装 <code>file</code>、<code>fakeroot</code></td></tr></tbody></table><h2 id="资源嵌入" tabindex="-1">资源嵌入 <a class="header-anchor" href="#资源嵌入" aria-label="Permalink to &quot;资源嵌入&quot;">​</a></h2><p>打包过程中自动处理以下资源：</p><table tabindex="0"><thead><tr><th>资源类型</th><th>说明</th></tr></thead><tbody><tr><td>应用图标</td><td>自动转换为各平台格式（<code>.ico</code> / <code>.icns</code> / <code>.png</code>）</td></tr><tr><td>版本信息</td><td>自动嵌入到可执行文件中</td></tr><tr><td>Manifest 文件</td><td>Windows 下自动生成并嵌入</td></tr><tr><td>框架运行时</td><td>自动打包必要的框架库文件（<code>libenergy.dylib</code> / <code>libenergy.so</code>）</td></tr></tbody></table>`,75),n=[s];function r(i,c,l,p,h,b){return d(),e("div",null,n)}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
